//! Burn autograd fuzz

//! input: AutogradProgram AST generated by arbitrary
//! env config: FUZZ_MAX_LEAVES (default 4), FUZZ_MODE (default panic)
//! 
//! fuzz_autograd -> FuzzConfig to get environmental variables 
//! ->  interpreter.rs -> run_autograd_program -> collect grads to acutally run the DAG and call backward()
//! collect_grads -> step_diff -> resolve_ref -> dispatch_leaf to actually step through our DAG node by node, and then resolve the reference for nodes that we need to by "indexing" based on our "leaf ID u8" 
//! compares with run_autograd_oracle

#![no_main]

use fuzzburn::ir::{interpreter, program::AutogradProgram, FuzzConfig};
use libfuzzer_sys::fuzz_target;

fuzz_target!(|prog: AutogradProgram| {
    let config = FuzzConfig::from_env();
    println!("=== Fuzz input (max_leaves={}) ===\n{}", config.max_leaves, prog.ssa(config.max_leaves));
    interpreter::run_autograd_program(&prog, &config);
});
